styling.css:
.card {
 font-family: google sans;
 font-size: 20px;
 text-align: center;
 color: black;
 background-color: white;
}

.tc-shell {
  --topic: #2563eb;
  --accent: #38bdf8;
  box-sizing: border-box;
  min-height: 100vh;
  display: grid;
  place-items: center;
  padding: 28px;
  text-align: left;
  color: #202124;
  font-family: Inter, "Segoe UI", system-ui, -apple-system, BlinkMacSystemFont, "Noto Sans SC", "Microsoft YaHei", sans-serif;
  background: linear-gradient(120deg, rgba(37, 99, 235, 0.08), transparent 28%), linear-gradient(240deg, rgba(220, 38, 38, 0.08), transparent 30%), #f6f2ea;
}
.tc-frame { width: min(1120px, 100%); display: grid; gap: 18px; }
.tc-single { min-height: min(560px, 70vh); }
.tc-two { grid-template-columns: minmax(0, 1fr) minmax(320px, 420px); align-items: stretch; }
.tc-card { box-sizing: border-box; border: 1px solid color-mix(in srgb, var(--topic), #ffffff 48%); border-radius: 8px; background: #fffdf8; box-shadow: 0 18px 46px rgba(37, 31, 22, 0.14); }
.tc-question { min-height: min(560px, 70vh); display: grid; grid-template-rows: auto 1fr auto; gap: 18px; padding: clamp(24px, 5vw, 56px); }
.tc-answer { max-height: min(560px, 70vh); overflow: auto; padding: 18px 14px; background: rgba(255,255,255,0.88); }
.tc-kicker { color: var(--topic); font-size: 13px; line-height: 1.2; font-weight: 950; text-transform: uppercase; }
.tc-main { align-self: center; display: block; color: var(--topic); font-size: clamp(42px, 6vw, 76px); line-height: 1.12; font-weight: 850; letter-spacing: 0; overflow-wrap: anywhere; }
.tc-main > div:first-child, .tc-main strong, .tc-main b { color: var(--topic) !important; font-size: inherit !important; line-height: inherit !important; font-weight: 850 !important; }
.tc-front-copy { font-size: clamp(28px, 4vw, 48px); }
.tc-hint { color: #69645b; font-size: 13px; font-weight: 850; }
.tc-answer-body { color: #202124; font-size: 16px; line-height: 1.55; }
.tc-answer-body > div:first-child { margin: 0 0 12px; color: #111827; font-size: 24px !important; line-height: 1.15 !important; font-weight: 900 !important; }
.tc-answer-body hr { height: 1px; border: 0; margin: 14px 0; background: #e3dbce; }
.tc-answer-body ul { display: grid; gap: 10px; margin: 12px 0 0; padding: 0; list-style: none; }
.tc-answer-body li, .tc-block { display: block; padding: 12px; border-radius: 8px; background: #fff; box-shadow: 0 8px 20px rgba(37, 31, 22, 0.08); }
.tc-answer-body li b, .tc-block b { color: #111827; font-weight: 900; }
.tc-answer-body span[style*="color:#666"], .tc-answer-body span[style*="color: #666"], .tc-answer-body span[style*="color:#444"], .tc-answer-body span[style*="color: #444"] { color: #69645b !important; }
.tc-answer-body div[style], .tc-answer-body span[style] { font-family: inherit !important; }
.nightMode .tc-shell { background: #181715; color: #f6f2ea; }
.nightMode .tc-card { background: #22201d; color: #f6f2ea; border-color: color-mix(in srgb, var(--topic), #22201d 32%); }
.nightMode .tc-answer-body, .nightMode .tc-answer-body > div:first-child, .nightMode .tc-answer-body li b, .nightMode .tc-block b { color: #f6f2ea; }
.nightMode .tc-answer-body li, .nightMode .tc-block { background: #2b2925; }
@media (max-width: 760px) {
  .tc-shell { padding: 10px; align-items: start; }
  .tc-two { grid-template-columns: 1fr; }
  .tc-question { min-height: 36vh; padding: 18px; }
  .tc-answer { max-height: none; }
  .tc-main { font-size: clamp(30px, 9vw, 48px); }
  .tc-front-copy { font-size: clamp(24px, 7vw, 38px); }
}

